const data = $input.first().json;

const severity = (data.confidence >= 85) ? '🔴 HIGH' : (data.confidence >= 70) ? '🟠 MEDIUM' : '🟡 LOW';
const statusEmoji = data.status === 'failure' ? '❌' : '✅';

return [{
  json: {
    blocks: JSON.stringify([
      {
        type: 'header',
        text: {
          type: 'plain_text',
          text: `${statusEmoji} CI Failure Detected`,
          emoji: true
        }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Pipeline:*\n${data.pipeline || data.name || 'unknown'}` },
          { type: 'mrkdwn', text: `*Branch:*\n${data.branch || 'main'}` },
          { type: 'mrkdwn', text: `*Severity:*\n${severity}` },
          { type: 'mrkdwn', text: `*Confidence:*\n${data.confidence || 0}%` }
        ]
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Root Cause:*\n>${data.error || data.root_cause || 'See Aeon dashboard for details'}`
        }
      },
      {
        type: 'actions',
        elements: [
          {
            type: 'button',
            text: { type: 'plain_text', text: 'View in Aeon', emoji: true },
            url: `http://localhost:3000/ai`,
            style: 'primary'
          },
          data.url ? {
            type: 'button',
            text: { type: 'plain_text', text: 'View Build', emoji: true },
            url: data.url
          } : null
        ].filter(Boolean)
      },
      { type: 'divider' },
      {
        type: 'context',
        elements: [{
          type: 'mrkdwn',
          text: `🤖 Analyzed by Aeon AI · ${new Date().toLocaleString()}`
        }]
      }
    ]),
    channel: '#ci-alerts',
    text: `CI Failure: ${data.pipeline || 'build'} failed on ${data.branch || 'main'}`
  }
}];
